#include "fxp.h"

#if FFT_SIZE == 8

  #define TEST_CASE 0

  #if TEST_CASE == 0
    /*
    * Interleaved complex input: [Re0, Im0, Re1, Im1, ...]
    * Q16.15 format
    *
    * Test vector: delta[n] = 1 at n=0, else 0
    * => FFT output X[k] = 1 + j0 for all k
    */
    int32_t input_signal[2 * FFT_SIZE] = {
      32768, 0,   // x[0] = 1 + j0
          0, 0,   // x[1]
          0, 0,   // x[2]
          0, 0,   // x[3]
          0, 0,   // x[4]
          0, 0,   // x[5]
          0, 0,   // x[6]
          0, 0    // x[7]
    };

    int32_t exp_output_real[FFT_SIZE] = {
      32768, 32768, 32768, 32768, 32768, 32768, 32768, 32768
    };

    int32_t exp_output_imag[FFT_SIZE] = {
      0, 0, 0, 0, 0, 0, 0, 0
    };

  #elif TEST_CASE == 1
    /*
    * Test vector 1: DC Signal (All 1s)
    * Input: x[n] = 1 + j0 for all n
    * Checks for overflow in the DC bin (X[0]).
    * Expected: X[0] = 8 + j0 (if no internal scaling is applied), others 0
    */
    int32_t input_signal[2 * FFT_SIZE] = {
      32768, 0,   // x[0]
      32768, 0,   // x[1]
      32768, 0,   // x[2]
      32768, 0,   // x[3]
      32768, 0,   // x[4]
      32768, 0,   // x[5]
      32768, 0,   // x[6]
      32768, 0    // x[7]
    };

    // 8.0 en Q16.15 es 8 * 32768 = 262144
    int32_t exp_output_real[FFT_SIZE] = {
      262144, 0, 0, 0, 0, 0, 0, 0
    };

    int32_t exp_output_imag[FFT_SIZE] = {
      0, 0, 0, 0, 0, 0, 0, 0
    };

  #elif TEST_CASE == 2
    /*
    * Test vector 2: Nyquist Frequency (Alternating 1 and -1)
    * Input: x[n] = (-1)^n + j0
    * Checks energy accumulation at the highest frequency bin (X[N/2]).
    * Expected: X[4] = 8 + j0, others 0
    */
    int32_t input_signal[2 * FFT_SIZE] = {
      32768, 0,   // x[0] =  1
      -32768, 0,   // x[1] = -1
      32768, 0,   // x[2] =  1
      -32768, 0,   // x[3] = -1
      32768, 0,   // x[4] =  1
      -32768, 0,   // x[5] = -1
      32768, 0,   // x[6] =  1
      -32768, 0    // x[7] = -1
    };

    int32_t exp_output_real[FFT_SIZE] = {
      0, 0, 0, 0, 262144, 0, 0, 0
    };

    int32_t exp_output_imag[FFT_SIZE] = {
      0, 0, 0, 0, 0, 0, 0, 0
    };


  #elif TEST_CASE == 3
    /*
    * Test vector 3: Shifted Impulse
    * Input: x[4] = 1 + j0, others 0
    * Checks phase rotation and twiddle factor application.
    * Expected: X[k] = (-1)^k
    */
    int32_t input_signal[2 * FFT_SIZE] = {
          0, 0,   // x[0]
          0, 0,   // x[1]
          0, 0,   // x[2]
          0, 0,   // x[3]
      32768, 0,   // x[4] = 1 + j0
          0, 0,   // x[5]
          0, 0,   // x[6]
          0, 0    // x[7]
    };

    int32_t exp_output_real[FFT_SIZE] = {
      32768, -32768,  32768, -32768,  32768, -32768,  32768, -32768
    };

    int32_t exp_output_imag[FFT_SIZE] = {
      0, 0, 0, 0, 0, 0, 0, 0
    };
  #endif // TEST_CASE
#endif // FFT_SIZE == 8

